choose.otherwise:
SELECT id_device, ${field_data_name} as value FROM ${datatablename} d WHERE d.id_device = #{id_device}
AND d.${field_data_name} < #{threshold}
AND d.${field_data_name} > #{threshold}
AND d.${field_data_name} = #{threshold}
AND d.`time` BETWEEN CONVERT_TZ(CONCAT(CURDATE(), ' ', #{time_from}), #{time_zone_offset}, '+00:00') AND CONVERT_TZ(CONCAT(CURDATE(), ' ', #{time_to}), #{time_zone_offset}, '+00:00')
AND ( d.`time` >= CONVERT_TZ(CONCAT(CURDATE(), ' ', #{time_from}), #{time_zone_offset}, '+00:00') OR d.`time` < CONVERT_TZ(CONCAT(DATE_ADD(CURDATE(), INTERVAL 1 DAY), ' ', #{time_to} ), #{time_zone_offset}, '+00:00') )
ORDER BY d.`time` DESC LIMIT 1

mapper.insert:
INSERT INTO alert_queue (
    id_device,
    id_error,
    start_date,
    open_send_mail,
    is_notification
) VALUES(
    #{id_device},
    (
        SELECT e.id
        FROM error e
        WHERE
        e.id_device_group = #{id_device_group}
        AND e.custom_alert_tag = #{custom_alert_tag}
        LIMIT 1
    ),
    NOW(),
    #{open_send_mail},
    #{is_notification}
);

mapper.select:
SELECT max(${field}) as value FROM ${datatablename} d WHERE id_device = #{id_device}
AND d.`time` BETWEEN CONVERT_TZ(CONCAT(CURDATE(), ' ', #{time_from}), #{time_zone_offset}, '+00:00') AND CONVERT_TZ(CONCAT(CURDATE(), ' ', #{time_to}), #{time_zone_offset}, '+00:00')
AND ( d.`time` >= CONVERT_TZ(CONCAT(CURDATE(), ' ', #{time_from}), #{time_zone_offset}, '+00:00') OR d.`time` < CONVERT_TZ(CONCAT(DATE_ADD(CURDATE(), INTERVAL 1 DAY), ' ', #{time_to} ), #{time_zone_offset}, '+00:00') )
